import { describe, expect, it } from 'vitest';

import {
  BANDWIDTH_HEXON,
  BANDWIDTH_TRIHEXENNEON,
  BANDWIDTH_TRITON,
  EvolutionResolutionMaster,
  OneWayMirrorMaster,
  bandwidthGapStrict,
  buleStepCost,
  buleStepCostInvariantUnderBandwidthChange,
  carrierBandwidth,
  copyIndexExceedsTritonBandwidth,
  eighteenToOneCollision,
  evolutionTriggerAtBandwidthMinusOne,
  isEvolutionStep,
  isResolutionStep,
  lensDownToTriton,
  lensTritonThreeFibers,
  lowerObserverCannotDistinguishFirstTriton,
  stepEitherOr,
  stepNotBoth,
  tritonStretchTriplesBandwidth,
} from '../src/pleromatic-bandwidth';

describe('Carrier bandwidth — base values', () => {
  it('Triton bandwidth is 3 (bandwidth_triton)', () => {
    expect(BANDWIDTH_TRITON).toBe(3);
    expect(carrierBandwidth(3)).toBe(3);
  });

  it('Hexon bandwidth is 6', () => {
    expect(BANDWIDTH_HEXON).toBe(6);
    expect(carrierBandwidth(6)).toBe(6);
  });

  it('Trihexenneon bandwidth is 54 (bandwidth_trihexenneon)', () => {
    expect(BANDWIDTH_TRIHEXENNEON).toBe(54);
    expect(carrierBandwidth(54)).toBe(54);
  });

  it('bandwidth gap is strict: 54 > 3', () => {
    expect(bandwidthGapStrict()).toBe(true);
  });

  it('Trihexenneon = 18 × Triton', () => {
    expect(BANDWIDTH_TRIHEXENNEON).toBe(18 * BANDWIDTH_TRITON);
  });
});

describe('Triton stretch triples bandwidth', () => {
  it('holds at n = 0..5 (triton_stretch_triples_bandwidth)', () => {
    for (let n = 0; n <= 5; n++) {
      expect(tritonStretchTriplesBandwidth(n)).toBe(true);
    }
  });
});

describe('Lens-down to Triton — 18-fold compression', () => {
  it('compresses 18n to n (lens_down_triton_compression)', () => {
    for (let n = 0; n <= 3; n++) {
      expect(lensDownToTriton(18 * n)).toBe(n);
    }
  });

  it('boundary 17 → 0 and 18 → 1 (lens_triton_boundary_seventeen_eighteen)', () => {
    expect(lensDownToTriton(17)).toBe(0);
    expect(lensDownToTriton(18)).toBe(1);
  });

  it('three-fiber tile-out (lens_triton_three_fibers)', () => {
    expect(lensDownToTriton(0)).toBe(0);
    expect(lensDownToTriton(17)).toBe(0);
    expect(lensDownToTriton(18)).toBe(1);
    expect(lensDownToTriton(35)).toBe(1);
    expect(lensDownToTriton(36)).toBe(2);
    expect(lensDownToTriton(53)).toBe(2);

    const fibers = lensTritonThreeFibers();
    expect(fibers.fiber0).toEqual([0, 0]);
    expect(fibers.fiber1).toEqual([1, 1]);
    expect(fibers.fiber2).toEqual([2, 2]);
  });

  it('lower observer cannot distinguish positions in [0,18)', () => {
    const samples: Array<[number, number]> = [
      [0, 1],
      [0, 17],
      [3, 11],
      [7, 16],
      [9, 9],
    ];
    for (const [a, b] of samples) {
      expect(lowerObserverCannotDistinguishFirstTriton(a, b)).toBe(true);
    }
  });

  it('eighteen-to-one collision: 0..17 all map to 0', () => {
    expect(eighteenToOneCollision()).toBe(true);
  });

  it('copy-index 18 exceeds Triton bandwidth 3', () => {
    expect(copyIndexExceedsTritonBandwidth()).toBe(true);
  });
});

describe('Evolution vs Resolution — dual phenomenology of +1', () => {
  it('isEvolutionStep at (3, 2) is true (triton_step_two_three_is_evolution)', () => {
    expect(isEvolutionStep(BANDWIDTH_TRITON, 2)).toBe(true);
  });

  it('isEvolutionStep at (54, 2) is false (same step, higher bandwidth)', () => {
    expect(isEvolutionStep(BANDWIDTH_TRIHEXENNEON, 2)).toBe(false);
  });

  it('isResolutionStep at (3, 2) is false', () => {
    expect(isResolutionStep(BANDWIDTH_TRITON, 2)).toBe(false);
  });

  it('isResolutionStep at (54, 2) is true (trihexenneon_step_two_three_is_resolution)', () => {
    expect(isResolutionStep(BANDWIDTH_TRIHEXENNEON, 2)).toBe(true);
  });

  it('step 5→6 dual reading: evolution at Hexon (6), resolution at Trihexenneon (54)', () => {
    expect(isEvolutionStep(BANDWIDTH_HEXON, 5)).toBe(true);
    expect(isResolutionStep(BANDWIDTH_TRIHEXENNEON, 5)).toBe(true);
  });

  it('Trihexenneon step 53→54 is evolution (trihexenneon_step_fiftythree_fiftyfour_is_evolution)', () => {
    expect(isEvolutionStep(BANDWIDTH_TRIHEXENNEON, 53)).toBe(true);
  });

  it('stepEitherOr is always true at varied bandwidths and positions', () => {
    const cases: Array<[number, number]> = [
      [BANDWIDTH_TRITON, 0],
      [BANDWIDTH_TRITON, 2],
      [BANDWIDTH_TRITON, 7],
      [BANDWIDTH_HEXON, 4],
      [BANDWIDTH_HEXON, 5],
      [BANDWIDTH_TRIHEXENNEON, 0],
      [BANDWIDTH_TRIHEXENNEON, 53],
      [BANDWIDTH_TRIHEXENNEON, 100],
    ];
    for (const [bw, k] of cases) {
      expect(stepEitherOr(bw, k)).toBe(true);
    }
  });

  it('stepNotBoth holds at varied bandwidths and positions', () => {
    const cases: Array<[number, number]> = [
      [BANDWIDTH_TRITON, 0],
      [BANDWIDTH_TRITON, 2],
      [BANDWIDTH_HEXON, 5],
      [BANDWIDTH_TRIHEXENNEON, 2],
      [BANDWIDTH_TRIHEXENNEON, 53],
    ];
    for (const [bw, k] of cases) {
      expect(stepNotBoth(bw, k)).toBe(true);
    }
  });

  it('evolution trigger at bandwidth - 1 (bw=3, 6, 54)', () => {
    expect(evolutionTriggerAtBandwidthMinusOne(BANDWIDTH_TRITON)).toBe(true);
    expect(evolutionTriggerAtBandwidthMinusOne(BANDWIDTH_HEXON)).toBe(true);
    expect(evolutionTriggerAtBandwidthMinusOne(BANDWIDTH_TRIHEXENNEON)).toBe(true);
  });
});

describe('Bule step cost is invariant', () => {
  it('buleStepCost is always 1', () => {
    expect(buleStepCost(BANDWIDTH_TRITON, 0)).toBe(1);
    expect(buleStepCost(BANDWIDTH_TRITON, 2)).toBe(1);
    expect(buleStepCost(BANDWIDTH_HEXON, 5)).toBe(1);
    expect(buleStepCost(BANDWIDTH_TRIHEXENNEON, 53)).toBe(1);
    expect(buleStepCost(0, 0)).toBe(1);
    expect(buleStepCost(999, 999)).toBe(1);
  });

  it('cost is invariant under bandwidth change', () => {
    expect(
      buleStepCostInvariantUnderBandwidthChange(
        BANDWIDTH_TRITON,
        BANDWIDTH_TRIHEXENNEON,
        2,
      ),
    ).toBe(true);
    expect(
      buleStepCostInvariantUnderBandwidthChange(
        BANDWIDTH_HEXON,
        BANDWIDTH_TRIHEXENNEON,
        5,
      ),
    ).toBe(true);
    expect(buleStepCostInvariantUnderBandwidthChange(1, 100, 50)).toBe(true);
  });
});

describe('Master bundles', () => {
  it('OneWayMirrorMaster bundles bandwidth gap + compression + copy-index', () => {
    expect(OneWayMirrorMaster.bandwidthGapStrict).toBe(true);
    expect(OneWayMirrorMaster.compressionFactor).toBe(18);
    expect(OneWayMirrorMaster.copyIndexExceedsTritonBandwidth).toBe(true);
    expect(OneWayMirrorMaster.eighteenToOneCollision).toBe(true);
    expect(OneWayMirrorMaster.trihexenneonIs18xTriton).toBe(true);
  });

  it('EvolutionResolutionMaster bundles exclusivity + exhaustiveness + sample readings', () => {
    expect(EvolutionResolutionMaster.exclusivityAtTritonStep2).toBe(true);
    expect(EvolutionResolutionMaster.exhaustivenessAtTritonStep2).toBe(true);
    expect(EvolutionResolutionMaster.triton_step_two_three_isEvolution).toBe(true);
    expect(
      EvolutionResolutionMaster.trihexenneon_step_two_three_isResolution,
    ).toBe(true);
    expect(EvolutionResolutionMaster.hexon_step_five_six_isEvolution).toBe(true);
    expect(
      EvolutionResolutionMaster.trihexenneon_step_five_six_isResolution,
    ).toBe(true);
    expect(EvolutionResolutionMaster.trihexenneon_step_53_54_isEvolution).toBe(
      true,
    );
    expect(EvolutionResolutionMaster.costAlwaysOne).toBe(true);
    expect(EvolutionResolutionMaster.costInvariantUnderBandwidth).toBe(true);
  });
});
